local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("latter", function(inst, time, task, taskName)     if not inst or not inst.DoTaskInTime then         return     end     if TD.isStr(taskName) then         TD.removeTask(inst, taskName)     end     local function temp()         local task = task or TD.empty         task()         if TD.isStr(taskName) then             TD.removeTask(inst, taskName)         end     end     local tmp = inst:DoTaskInTime(time or 1, temp)     if string.td1madao_notEmpty(taskName) then         inst[taskName] = tmp     end     return tmp end) TD.createFn("period", function(inst, name, fun, period, cleanTime, cleanFn)     if not inst then         return     end     if not name then         TD.default(inst, "td1madao_doPeriodicTask_task_adder", 0)         name = "td1madao_doPeriodicTask_task_adder" .. tostring(inst.td1madao_doPeriodicTask_task_adder)         inst.td1madao_doPeriodicTask_task_adder = inst.td1madao_doPeriodicTask_task_adder + 1     end     TD.removeTask(inst, name)     TD.removeTask(inst, name .. "Cleaner")     inst[name] = inst:DoPeriodicTask(period or 1, fun)     inst[name .. "Cleaner"] = inst:DoTaskInTime(cleanTime or 1, function()         if cleanFn then             cleanFn()         end         TD.removeTask(inst, name)         TD.removeTask(inst, name .. "Cleaner")     end) end) TD.createFn("removeTask", function(inst, task, fun)     if inst and inst[task] ~= nil then         inst[task]:Cancel()         inst[task] = nil     end     if fun then         fun()     end end) 